const config = $('Configuration').item.json;
const repos = config.scanRepos.split(',').map(r => r.trim());
return repos.map(repo => ({ repoName: repo, repoOwner: config.repoOwner }));

const gqlResponse = $('Fetch All Branches').item.json;
const mergedPRsRaw = $('Fetch Recently Merged PRs').item.json;
const config = $('Configuration').item.json;

const now = new Date();
const staleThreshold = new Date(now - config.staleDays * 24 * 3600 * 1000);

const protectedPatterns = config.protectedBranches.split(',').map(p => p.trim());

function isProtected(branchName) {
  return protectedPatterns.some(pattern => {
    if (pattern.includes('*')) {
      const regex = new RegExp('^' + pattern.replace(/\*/g, '.*') + '$');
      return regex.test(branchName);
    }
    return pattern === branchName;
  });
}

// Build merged branch set from PRs
const mergedBranchNames = new Set();
if (Array.isArray(mergedPRsRaw)) {
  for (const pr of mergedPRsRaw) {
    if (pr.merged_at && pr.head && pr.head.ref) {
      mergedBranchNames.add(pr.head.ref);
    }
  }
}

// Parse GraphQL response: data.repository.refs.nodes
const nodes = gqlResponse?.data?.repository?.refs?.nodes || [];
const branches = nodes.map(n => ({
  name: n.name,
  lastCommitDate: n.target?.committedDate || null
}));

const candidates = [];
let totalBranches = branches.length;
let protectedCount = 0;

for (const branch of branches) {
  // Skip invalid branch names (empty, whitespace-only, literal "-")
  if (!branch.name || branch.name.trim() === "" || branch.name.trim() === "-") continue;
  if (isProtected(branch.name)) {
    protectedCount++;
    continue;
  }

  let reason = '';
  let ageDays = 0;
  let lastCommitDateStr = 'unknown';

  if (mergedBranchNames.has(branch.name)) {
    reason = 'merged';
    if (branch.lastCommitDate) {
      const lastActive = new Date(branch.lastCommitDate);
      ageDays = Math.round((now - lastActive) / 86400000);
      lastCommitDateStr = lastActive.toISOString().split('T')[0];
    }
  } else if (branch.lastCommitDate) {
    const lastActive = new Date(branch.lastCommitDate);
    ageDays = Math.round((now - lastActive) / 86400000);
    lastCommitDateStr = lastActive.toISOString().split('T')[0];

    if (lastActive < staleThreshold) {
      reason = 'stale';
    } else {
      continue; // active branch, skip
    }
  } else {
    // No commit date available — treat as potentially stale
    reason = 'stale';
    lastCommitDateStr = 'unknown';
  }

  candidates.push({
    branchName: branch.name,
    lastCommitDate: lastCommitDateStr,
    ageDays,
    reason
  });
}

const toDelete = candidates.slice(0, config.maxBranchesToDelete);

return {
  repoName: config.scanRepos.split(',')[0] || 'unknown',
  repoOwner: config.repoOwner,
  reportDate: now.toISOString().split('T')[0],
  totalBranches,
  protectedCount,
  staleCandidates: candidates.length,
  mergedCandidates: candidates.filter(c => c.reason === 'merged').length,
  staleCandidatesCount: candidates.filter(c => c.reason === 'stale').length,
  toDelete: toDelete,
  willDeleteCount: toDelete.length,
  reportOnly: config.reportOnly
};

const data = $('Classify Branches — Merged vs Stale').item.json;

let lines = [];
lines.push(`*🧹 Weekly Branch Cleanup Report — ${data.reportDate}*`);
lines.push('');
lines.push(`*Repository:* ${data.repoOwner}/${data.repoName}`);
lines.push(`• Total branches: ${data.totalBranches}`);
lines.push(`• Protected (skipped): ${data.protectedCount}`);
lines.push(`• Stale candidates: ${data.staleCandidatesCount} (${$('Configuration').item.json.staleDays}+ days)`);
lines.push(`• Merged but not deleted: ${data.mergedCandidates}`);
lines.push(`• Ready for cleanup: ${data.willDeleteCount}/${data.staleCandidates + data.mergedCandidates}`);

if (data.reportOnly) {
  lines.push('');
  lines.push('📋 *Report-only mode* — no branches deleted.');
  lines.push(`Set 'reportOnly' to \`false\` in config to enable auto-deletion.`);
}

if (data.toDelete.length > 0) {
  lines.push('');
  lines.push(`*Top ${Math.min(10, data.toDelete.length)} cleanup candidates:*`);
  for (const b of data.toDelete.slice(0, 10)) {
    const icon = b.reason === 'merged' ? '🔀' : '⏳';
    lines.push(`  ${icon} \`${b.branchName}\` — ${b.ageDays}d old (${b.reason})`);
  }
}

return { message: lines.join('\n') };

const candidates = $('Classify Branches — Merged vs Stale').item.json.toDelete;

return candidates.map(b => ({
  branchName: b.branchName,
  reason: b.reason,
  repoOwner: $('Classify Branches — Merged vs Stale').item.json.repoOwner,
  repoName: $('Classify Branches — Merged vs Stale').item.json.repoName
}));

const deleted = $input.all().filter(i => !i.json.error).length;
const failed = $input.all().filter(i => i.json.error).length;

return {
  totalDeleted: deleted,
  totalFailed: failed,
  summary: `Deleted ${deleted} branches. ${failed > 0 ? `${failed} failed.` : 'All successful.'}`
};

